    28→        title: article.title,
    29→        displaytitle: article.displaytitle,
    30→        pageid: article.pageid
    31→    });
    32→
    33→    const handleShare = async () => {
    34→        if (navigator.share) {
    35→            try {
    36→                await navigator.share({
    37→                    title: article.displaytitle,
    38→                    text: article.extract || '',
    39→                    url: article.url
    40→                });
    41→            } catch (error) {
    42→                console.error('Error sharing:', error);
    43→            }
    44→        } else {
    45→            // Fallback: Copy to clipboard
    46→            await navigator.clipboard.writeText(article.url);
    47→            alert('Link copied to clipboard!');
    48→        }
    49→    };
    50→
    51→    return (
    52→        <div className="h-screen w-full flex items-center justify-center snap-start relative" onDoubleClick={() => toggleLike(article)}>
    53→            <div className="h-full w-full relative">
