import { http, HttpResponse } from 'msw';

const placeholderImage =
  'data:image/gif;base64,R0lGODlhAQABAIAAAAAAAP///yH5BAEAAAAALAAAAAABAAEAAAIBRAA7';

function makeWikiPage(id: number, title: string, extract: string) {
  return {
    pageid: id,
    title,
    varianttitles: { en: title },
    extract,
    thumbnail: {
      source: placeholderImage,
      width: 800,
      height: 600,
    },
    canonicalurl: `https://en.wikipedia.org/wiki/${title.replace(/ /g, '_')}`,
  };
}

export const mswHandlers = [
  http.get('https://en.wikipedia.org/w/api.php', () =>
    HttpResponse.json({
      query: {
        pages: {
          '12345': makeWikiPage(
            12345,
            'Eiffel Tower',
            'The Eiffel Tower is a wrought-iron lattice tower on the Champ de Mars in Paris, France. Named after the engineer Gustave Eiffel, whose company designed and built the tower from 1887 to 1889.'
          ),
          '12346': makeWikiPage(
            12346,
            'Great Wall of China',
            'The Great Wall of China is a series of fortifications built across the historical northern borders of ancient Chinese states and empires.'
          ),
          '12347': makeWikiPage(
            12347,
            'Colosseum',
            'The Colosseum is an oval amphitheatre in the centre of the city of Rome, Italy, just east of the Roman Forum.'
          ),
        },
      },
    })
  ),
];

import type { Preview } from '@storybook/react-vite';
import { initialize, mswLoader } from 'msw-storybook-addon';
import '../src/index.css';
import { LikedArticlesProvider } from '../src/contexts/LikedArticlesContext';
import { mswHandlers } from './msw-handlers';

initialize({
  onUnhandledRequest: 'bypass',
});

const preview: Preview = {
  decorators: [
    (Story) => (
      <LikedArticlesProvider>
        <Story />
      </LikedArticlesProvider>
    ),
  ],
  loaders: [mswLoader],
  parameters: {
    controls: {
      matchers: {
        color: /(background|color)$/i,
        date: /Date$/i,
      },
    },
    a11y: {
      test: 'todo',
    },
    msw: {
      handlers: mswHandlers,
    },
  },
  async beforeEach() {
    localStorage.setItem('lang', 'en');
    localStorage.removeItem('likedArticles');
  },
};

export default preview;

import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect, within, userEvent } from 'storybook/test';
import { WikiCard, type WikiArticle } from './WikiCard';

const mockArticle: WikiArticle = {
  pageid: 12345,
  title: 'Eiffel Tower',
  displaytitle: 'Eiffel Tower',
  extract:
    'The Eiffel Tower is a wrought-iron lattice tower on the Champ de Mars in Paris, France. Named after the engineer Gustave Eiffel, whose company designed and built the tower from 1887 to 1889.',
  thumbnail: {
    source:
      'data:image/gif;base64,R0lGODlhAQABAIAAAAAAAP///yH5BAEAAAAALAAAAAABAAEAAAIBRAA7',
    width: 800,
    height: 600,
  },
  url: 'https://en.wikipedia.org/wiki/Eiffel_Tower',
};

const meta = {
  component: WikiCard,
} satisfies Meta<typeof WikiCard>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Default: Story = {
  render: () => <WikiCard article={mockArticle} />,
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);
    await expect(
      canvas.getByRole('heading', { name: /eiffel tower/i })
    ).toBeVisible();
    await expect(canvas.getByText(/wrought-iron lattice tower/i)).toBeVisible();
    await expect(
      canvas.getByRole('button', { name: /like article/i })
    ).toBeVisible();
    await expect(
      canvas.getByRole('button', { name: /share article/i })
    ).toBeVisible();
    await expect(canvas.getByText(/read more/i)).toBeVisible();
  },
};

export const NoThumbnail: Story = {
  render: () => (
    <WikiCard
      article={
        { ...mockArticle, thumbnail: null } as unknown as WikiArticle
      }
    />
  ),
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);
    await expect(
      canvas.getByRole('heading', { name: /eiffel tower/i })
    ).toBeVisible();
    await expect(canvas.getByText(/wrought-iron lattice tower/i)).toBeVisible();
  },
};

export const Liked: Story = {
  render: () => <WikiCard article={mockArticle} />,
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);
    const likeButton = canvas.getByRole('button', { name: /like article/i });
    await expect(likeButton).not.toHaveClass('bg-red-500');
    await userEvent.click(likeButton);
    await expect(likeButton).toHaveClass('bg-red-500');
  },
};

import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect, within, userEvent } from 'storybook/test';
import { LanguageSelector } from './LanguageSelector';

const meta = {
  component: LanguageSelector,
} satisfies Meta<typeof LanguageSelector>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Default: Story = {
  render: () => (
    <div className="bg-black p-4">
      <LanguageSelector />
    </div>
  ),
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);
    await expect(
      canvas.getByRole('button', { name: /language/i })
    ).toBeVisible();
  },
};

export const Open: Story = {
  render: () => (
    <div className="bg-black p-4" style={{ height: '300px' }}>
      <LanguageSelector />
    </div>
  ),
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);
    const languageButton = canvas.getByRole('button', { name: /language/i });
    await userEvent.click(languageButton);
    await expect(canvas.getByText('English')).toBeVisible();
    await expect(canvas.getByText('Français')).toBeVisible();
    await expect(canvas.getByText('Deutsch')).toBeVisible();
  },
};

export const ClosedByClickOutside: Story = {
  render: () => (
    <div className="bg-black p-4" style={{ height: '300px' }}>
      <div data-testid="outside" style={{ padding: '8px', color: 'white' }}>
        Outside area
      </div>
      <LanguageSelector />
    </div>
  ),
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);
    const languageButton = canvas.getByRole('button', { name: /language/i });
    await userEvent.click(languageButton);
    await expect(canvas.getByText('English')).toBeVisible();
    await userEvent.click(canvas.getByTestId('outside'));
    await expect(canvas.queryByText('English')).not.toBeInTheDocument();
  },
};

import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect, within } from 'storybook/test';
import Article from './Article';

const meta = {
  component: Article,
} satisfies Meta<typeof Article>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Default: Story = {
  render: () => (
    <Article
      title="Eiffel Tower"
      content="The Eiffel Tower is a wrought-iron lattice tower on the Champ de Mars in Paris, France."
      image="data:image/gif;base64,R0lGODlhAQABAIAAAAAAAP///yH5BAEAAAAALAAAAAABAAEAAAIBRAA7"
    />
  ),
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);
    await expect(canvas.getByRole('article')).toBeVisible();
    await expect(
      canvas.getByRole('heading', { name: /eiffel tower/i })
    ).toBeVisible();
    await expect(canvas.getByText(/wrought-iron lattice tower/i)).toBeVisible();
    await expect(canvas.getByRole('img')).toBeVisible();
  },
};

export const NoImage: Story = {
  render: () => (
    <Article
      title="Great Wall of China"
      content="The Great Wall of China is a series of fortifications built across the historical northern borders of ancient Chinese states."
    />
  ),
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);
    await expect(canvas.getByRole('article')).toBeVisible();
    await expect(
      canvas.getByRole('heading', { name: /great wall/i })
    ).toBeVisible();
    await expect(canvas.queryByRole('img')).not.toBeInTheDocument();
  },
};

export const LongContent: Story = {
  render: () => (
    <Article
      title="Colosseum"
      content="The Colosseum is an oval amphitheatre in the centre of the city of Rome, Italy, just east of the Roman Forum. It is the largest ancient amphitheatre ever built, and is still the largest standing amphitheatre in the world today, despite its age. Construction began under the emperor Vespasian in AD 72 and was completed in AD 80 under his successor and heir, Titus. Further modifications were made during the reign of Domitian. The three emperors that were patrons of the work are known as the Flavian dynasty, and the amphitheatre was named in Latin as the Amphitheatrum Flavium. The Flavian Amphitheatre could hold between 50,000 and 80,000 spectators at various points of its history."
    />
